 	*p1++ = c;
+	if (ilen > BUFSIZ) {    /* avoir trashing the stack and get root */
+		ilen = BUFSIZ;
+		p2[ilen - 1] = '\0';
+	}
 	while ((c = *p2++) != '\0') {
 		*p1++ = (c == '\n') ? ' ' : c;

